mapper.select:
SELECT l.* FROM sys_operation_log l LEFT JOIN sys_user u ON l.operation_user_id=u.user_id
l.tenant_id = #{tenantId}
AND l.log_type = #{logType}
AND l.track_id LIKE CONCAT('%',#{trackId},'%')
AND u.username LIKE CONCAT('%',#{username},'%')
AND u.phone LIKE CONCAT('%',#{phone},'%')
AND l.operation_params LIKE CONCAT('%',#{operationParams},'%')
AND l.ip LIKE CONCAT('%',#{ip},'%')
AND l.address LIKE CONCAT('%',#{address},'%')
AND l.operation_time >= #{startTime} AND l.operation_time <= #{endTime}
AND l.`status` = #{status}
ORDER BY update_time DESC
